    auto span = m_tracer->startSpan("ai_hub.get_completions");
    span->setAttribute("file_path", filePath);
    span->setAttribute("prefix_length", prefix.length());
    
    if (!isReady()) {
        m_logger->warn("AI Hub not ready, returning empty completions");
        return {};
    }
    
    try {
        auto startTime = std::chrono::high_resolution_clock::now();
        
        // Get context from analyzer
        auto context = m_contextAnalyzer->analyzeContext(filePath, cursorPosition);
        
        // Route to appropriate model
        auto routingDecision = m_modelRouter->routeTask(
            TaskType::COMPLETION,
            prefix + context,
            Complexity::SIMPLE
        );
        
        // Check if model switching is needed
        if (routingDecision.selectedModel != m_currentModel) {
            m_logger->info("Switching model for completion: {} -> {}", 
                          m_currentModel, routingDecision.selectedModel);
            // For now, use current model - switching can be added later
        }
        
        // Get completions from engine
        auto completions = m_completionEngine->getContextualCompletions(
            filePath,
            cursorPosition / 1000, // approximate line
            cursorPosition % 1000, // approximate column
            context
        );
        
        auto endTime = std::chrono::high_resolution_clock::now();
        auto latency = std::chrono::duration_cast<std::chrono::microseconds>(endTime - startTime);
        
        m_metrics->recordHistogram("completion_latency_us", latency.count());
        span->setAttribute("completion_count", completions.size());
        span->setAttribute("latency_us", latency.count());
        
        return completions;
        
    } catch (const std::exception& e) {
        m_logger->error("Error getting completions: {}", e.what());
        m_metrics->incrementCounter("completion_errors");
